import math
from typing import Any

# ---------- 1. Guard expressions with named booleans ----------

MAX_LATENCY_MS = 2_000
MAX_ATTEMPTS = 5
FATAL_ERRORS = {"auth_failed", "quota_exceeded", "invalid_api_key"}

def should_retry(attempt: int, latency_ms: float, error_code: str) -> bool:
    """Readable guard: each condition on its own line."""
    within_attempts = attempt < MAX_ATTEMPTS
    acceptable_latency = latency_ms < MAX_LATENCY_MS
    recoverable = error_code not in FATAL_ERRORS
    return within_attempts and acceptable_latency and recoverable

# ---------- 2. Short-circuit as safety gate ----------

def load_model(name: str | None, registry: dict) -> Any | None:
    """Only look up the registry if name is non-empty."""
    return name and registry.get(name)   # returns None/falsy if name is falsy

# ---------- 3. Walrus operator in a streaming loop ----------

def drain_log_stream(stream) -> list[str]:
    """Assign and test in a single expression per iteration."""
    errors = []
    while (line := stream.readline()):   # assigns then tests
        if "ERROR" in line or "CRITICAL" in line:
            errors.append(line.rstrip())
    return errors

# ---------- 4. Dict merge with | operator ----------

BASE_CONFIG = {"model": "gpt-4o-mini", "temperature": 0.7, "max_tokens": 1024}

def build_request(overrides: dict) -> dict:
    """Non-mutating merge; right side wins on key conflicts."""
    return BASE_CONFIG | overrides   # Python 3.9+

# ---------- 5. Float comparison with tolerance ----------

PASS_THRESHOLD = 0.85

def passes_eval(score: float) -> bool:
    """Never use == for floats from ML scoring pipelines."""
    return score >= PASS_THRESHOLD or math.isclose(score, PASS_THRESHOLD, rel_tol=1e-6)

# ---------- 6. Membership in set for O(1) allowlist check ----------

ALLOWED_TOOLS = {"web_search", "code_exec", "file_read", "calculator"}

def is_tool_allowed(tool_name: str) -> bool:
    return tool_name in ALLOWED_TOOLS   # O(1) — constant regardless of set size

# ---------- 7. Chained comparisons for range validation ----------

def validate_confidence(conf: float) -> bool:
    return 0.0 <= conf <= 1.0   # equivalent to: 0.0 <= conf and conf <= 1.0

# ---------- 8. Walrus in conditional (list comprehension) ----------

def extract_high_confidence(results: list[dict]) -> list[dict]:
    """Compute confidence once, filter and use in one pass."""
    return [
        {"text": r["text"], "confidence": conf}
        for r in results
        if (conf := r.get("confidence", 0.0)) >= 0.8
    ]
